use aiken/collection/dict
use cardano/assets
use cardano/transaction.{Output, OutputReference, Transaction}

pub type FeeDatum {
  fee_table: dict.Dict<ByteArray, Int>,
  operation: ByteArray,
  default_fee: Int,
  max_allowed: Int,
}

pub type FeeRedeemer {
  fee_paid: Int,
}

fn lookup_fee(
  fee_table: dict.Dict<ByteArray, Int>,
  operation: ByteArray,
  default_fee: Int,
) -> Int {
  when dict.get(fee_table, operation) is {
    Some(fee) -> fee
    None -> default_fee
  }
}

fn get_output_lovelace(output: Output) -> Int {
  assets.lovelace_of(output.value)
}

validator default_fee_validator {
  spend(
    datum: Option<FeeDatum>,
    redeemer: FeeRedeemer,
    _ref: OutputReference,
    self: Transaction,
  ) -> Bool {
    when datum is {
      None -> False
      Some(fee_datum) -> {
        let required_fee =
          lookup_fee(
            fee_datum.fee_table,
            fee_datum.operation,
            fee_datum.default_fee,
          )
        let fee_paid = redeemer.fee_paid
        let within_max = required_fee <= fee_datum.max_allowed
        let sufficient_fee = fee_paid >= required_fee
        let outputs_cover_fee =
          list.any(
            self.outputs,
            fn(output) { get_output_lovelace(output) >= fee_paid },
          )
        within_max && sufficient_fee && outputs_cover_fee
      }
    }
  }

  else(_) {
    False
  }
}

use aiken/collection/dict
use cardano/crypto.{VerificationKeyHash}
use cardano/transaction.{Transaction}

pub type ConfigDatum {
  config: dict.Dict<ByteArray, Int>,
  key: ByteArray,
  min_val: Int,
}

validator config_registry(admin: ByteArray) {
  spend(
    datum: Option<ConfigDatum>,
    _redeemer: Data,
    _ref: cardano/transaction.OutputReference,
    self: Transaction,
  ) -> Bool {
    let admin_vkh: VerificationKeyHash = admin
    let admin_signed =
      self.extra_signatories |> list.has(admin_vkh)
    when datum is {
      None -> False
      Some(d) -> {
        let value_ok =
          when dict.get(d.config, d.key) is {
            None -> False
            Some(v) -> v >= d.min_val
          }
        admin_signed && value_ok
      }
    }
  }

  else(_) {
    fail
  }
}

use aiken/collection/dict
use cardano/transaction.{Transaction}
use cardano/crypto.{VerificationKeyHash}
use aiken/primitive/bytearray

pub type RemovalDatum {
  registry: dict.Dict<ByteArray, Int>,
  remove_key: ByteArray,
  owner: ByteArray,
}

fn verify_owner_signed(self: Transaction, owner: ByteArray) -> Bool {
  let vkh: VerificationKeyHash = owner
  list.has(self.extra_signatories, vkh)
}

validator entry_removal {
  spend(
    datum: Option<RemovalDatum>,
    _redeemer: Data,
    _ref: cardano/transaction.OutputReference,
    self: Transaction,
  ) -> Bool {
    when datum is {
      None -> False
      Some(d) -> {
        let owner_signed = verify_owner_signed(self, d.owner)
        let updated = dict.delete(d.registry, d.remove_key)
        let key_removed = !dict.has_key(updated, d.remove_key)
        owner_signed && key_removed
      }
    }
  }
}
